        [Test]
        public void DialogueFileRoundTripsRolesAndMultilineContent()
        {
            ChatMessage[] source =
            {
                ChatMessage.User("First line\nSecond line"),
                ChatMessage.Assistant("Answer with a \"quote\"."),
            };

            string text = ChatDialogueFile.Serialize(source);
            Assert.That(
                ChatDialogueFile.TryDeserialize(text, out List<ChatMessage> loaded, out string error),
                Is.True,
                error
            );
            Assert.That(
                loaded.Select(message => message.Role),
                Is.EqualTo(source.Select(message => message.Role))
            );
            Assert.That(
                loaded.Select(message => message.Content),
                Is.EqualTo(source.Select(message => message.Content))
            );
        }

        [Test]
        public void DialogueFileRejectsUnsupportedVersion()
        {
            bool valid = ChatDialogueFile.TryDeserialize(
                "{\"version\":2,\"messages\":[]}",
                out _,
                out string error
            );

            Assert.That(valid, Is.False);
            Assert.That(error, Does.Contain("version"));
        }

