        [Test]
        public void ImportedConversationReplacesHistoryAndKeepsSystemPrompt()
        {
            GameObject host = new(nameof(ImportedConversationReplacesHistoryAndKeepsSystemPrompt));
            try
            {
                CortexCore cortex = host.AddComponent<CortexCore>();
                typeof(CortexCore)
                    .GetField("systemPrompt", BindingFlags.Instance | BindingFlags.NonPublic)
                    .SetValue(cortex, "System prompt");
                ChatMessage[] imported =
                {
                    ChatMessage.User("Previous question"),
                    ChatMessage.Assistant("Previous answer"),
                };

                Assert.That(cortex.ReplaceConversation(imported), Is.True);
                var history = (List<ChatMessage>)
                    typeof(CortexCore)
                        .GetField("history", BindingFlags.Instance | BindingFlags.NonPublic)
                        .GetValue(cortex);
                Assert.That(
                    history.Select(message => message.Role),
                    Is.EqualTo(new[] { "system", "user", "assistant" })
                );
                Assert.That(
                    history.Select(message => message.Content),
                    Is.EqualTo(new[] { "System prompt", "Previous question", "Previous answer" })
                );
            }
            finally
            {
                Object.DestroyImmediate(host);
            }
        }

        [Test]
        public void TinyModelCannotBeSelectedAtRuntime()
        {
            GameObject host = new(nameof(TinyModelCannotBeSelectedAtRuntime));
            try
            {
                CortexCore cortex = host.AddComponent<CortexCore>();
                cortex.SystemOption = LlmSystemOption.Cpu1_7B_2048;
                Assert.That(cortex.SystemOption, Is.EqualTo(LlmSystemOption.Cpu1_7B_2048));

                // Persisted user config assigns straight through this setter, so the config
                // panel's locked-option check is not the only thing that has to refuse Tiny.
                LogAssert.ignoreFailingMessages = true;
                cortex.SystemOption = LlmSystemOption.Tiny;
                Assert.That(cortex.SystemOption, Is.EqualTo(LlmSystemOption.Cpu1_7B_2048));

                bool locked = cortex.TryGetEnumOption(
                    "ui_ai_select_model",
                    LlmSystemOption.Tiny,
                    out string label,
                    out bool enabled
                );
                Assert.That(locked, Is.True);
                Assert.That(enabled, Is.False);
                Assert.That(label, Does.Contain("test only"));
            }
            finally
            {
                LogAssert.ignoreFailingMessages = false;
                Object.DestroyImmediate(host);
            }
        }

