        [Test]
        public void CortexHeatGridMapsSignalsAndDecaysMonotonically()
        {
            CortexHeatGrid grid = new(16, 4, 2, 1f, 1.4f, 0.25f, 0.3f);
            grid.OnForward();

            CortexCellInfo structureCell = Enumerable
                .Range(0, grid.Width * grid.Height)
                .Select(index => grid.GetCell(index % grid.Width, index / grid.Width))
                .First(cell => cell.TransformerBlock == 2);
            Assert.That(structureCell.Branch, Is.EqualTo("attention"));
            Assert.That(structureCell.Stage, Is.Not.Empty);
            Assert.That(structureCell.Heat, Is.EqualTo(1f));

            TokenMetrics metrics = TokenMetrics.FromLogits(new[] { 0f, 1f, 2f }, 2);
            grid.OnToken(metrics);
            int tokenIndex = grid.TokenCellIndex(2);
            CortexCellInfo tokenCell = grid.GetCell(
                tokenIndex % grid.Width,
                tokenIndex / grid.Width
            );
            float heatBeforeDecay = tokenCell.Heat;

            Assert.That(tokenCell.Region, Is.EqualTo("token surface"));
            Assert.That(tokenCell.TokenId, Is.EqualTo(2));
            Assert.That(tokenCell.Probability, Is.EqualTo(0.665241f).Within(0.000001f));
            Assert.That(grid.TokenCellIndex(2), Is.EqualTo(tokenIndex));

            grid.Decay(0.5f);
            Assert.That(grid.Heat[tokenIndex], Is.GreaterThan(0f).And.LessThan(heatBeforeDecay));
        }

        [TestCase(28)]
        [TestCase(36)]
        public void CortexHeatGridMapsEveryTransformerBlock(int blockCount)
        {
            CortexHeatGrid grid = new(32, blockCount, 4, 1f, 1.4f, 0.25f, 0.3f);
            grid.OnForward();

            Assert.That(grid.TransformerBlockCount, Is.EqualTo(blockCount));
            Assert.That(grid.Width, Is.EqualTo(blockCount * CortexHeatGrid.ColumnsPerBlock));
            Assert.That(grid.Height, Is.EqualTo(grid.StructureRows + grid.TokenRows));
            for (int block = 0; block < blockCount; block++)
            {
                int x = block * CortexHeatGrid.ColumnsPerBlock;
                CortexCellInfo attention = grid.GetCell(x, grid.TokenRows);
                CortexCellInfo mlp = grid.GetCell(x + 1, grid.TokenRows);
                Assert.That(attention.TransformerBlock, Is.EqualTo(block));
                Assert.That(attention.Branch, Is.EqualTo("attention"));
                Assert.That(attention.Heat, Is.GreaterThan(0f));
                Assert.That(mlp.TransformerBlock, Is.EqualTo(block));
                Assert.That(mlp.Branch, Is.EqualTo("MLP"));
                Assert.That(mlp.Heat, Is.GreaterThan(0f));
            }
        }

        [TestCase(28)]
        [TestCase(36)]
        public void CortexMatrixVolumeBuildsOneQuadPerCell(int blockCount)
        {
            const int structureRows = 64;
            const int tokenRows = 8;
            int columns = blockCount * CortexHeatGrid.ColumnsPerBlock;
            MethodInfo build = typeof(CortexMatrixVolume).GetMethod(
                "BuildCellMesh",
                BindingFlags.Static | BindingFlags.NonPublic
            );
            Assert.That(build, Is.Not.Null);

            Mesh mesh = (Mesh)
                build.Invoke(
                    null,
                    new object[] { columns, structureRows, tokenRows, 0.72f, 1.08f, 0.3f }
                );
            try
            {
                int cellCount = columns * (structureRows + tokenRows);
                Assert.That(mesh.vertexCount, Is.EqualTo(cellCount * 4));
                Assert.That(mesh.GetIndexCount(0), Is.EqualTo((uint)(cellCount * 6)));
            }
            finally
            {
                Object.DestroyImmediate(mesh);
            }
        }

        [Test]
        public void CortexMatrixFoldedMappingClosesSeamAndLowersTokenDisk()
        {
            MethodInfo calculate = typeof(CortexMatrixVolume).GetMethod(
                "CalculateFoldedPosition",
                BindingFlags.Static | BindingFlags.NonPublic
            );
            Assert.That(calculate, Is.Not.Null);

            object[] Shape(float u, float vertical, bool token) =>
                new object[] { u, vertical, token, 0.72f, 1.08f, 0.3f };
            Vector3 seamStart = (Vector3)calculate.Invoke(null, Shape(0f, 0.5f, false));
            Vector3 seamEnd = (Vector3)calculate.Invoke(null, Shape(1f, 0.5f, false));
            Vector3 columnBottom = (Vector3)calculate.Invoke(null, Shape(0.25f, 0f, false));
            Vector3 diskOuter = (Vector3)calculate.Invoke(null, Shape(0.25f, 0f, true));

            Assert.That(Vector3.Distance(seamStart, seamEnd), Is.LessThan(0.0001f));
            Assert.That(diskOuter.y, Is.LessThan(columnBottom.y));
            Assert.That(
                new Vector2(diskOuter.x, diskOuter.z).magnitude,
                Is.EqualTo(1.08f).Within(0.0001f)
            );
        }

        [Test]
        public void CortexVisualizationRejectsHaloInsideColumn()
        {
            CortexVisualizationSettings settings = new();
            BindingFlags fields = BindingFlags.Instance | BindingFlags.NonPublic;
            void Set(string name, object value) =>
                typeof(CortexVisualizationSettings)
                    .GetField(name, fields)
                    .SetValue(settings, value);

            Set("stageRows", 64);
