        [Test]
        public void TinyModelGreedyGenerationIsDeterministic()
        {
            string modelPath = SentisModelPath("Llm_Tiny_Text_128.sentis");
            if (!File.Exists(modelPath))
                Assert.Ignore("Tiny .sentis model not converted yet: " + modelPath);

            ChatServiceOptions options = TinyUncachedOptions(modelPath);
            using ChatService service = new(options);
            ChatRuntimeInfo info = service.Start();
            Assert.That(info.ContextLength, Is.EqualTo(128));
            Assert.That(info.TransformerBlockCount, Is.EqualTo(4));

            // The tiny model has random weights and a 512-token vocabulary, so drive the raw
            // loop with small ids and disabled stop tokens to validate the decode mechanics.
            int[] prompt = { 2, 105, 10, 25, 50, 106 };
            ChatGenerationOptions generation = new() { MaxNewTokens = 8, Temperature = 0f };
            List<int> first = service.GenerateTokens(prompt, generation, Array.Empty<int>());
            List<int> second = service.GenerateTokens(prompt, generation, Array.Empty<int>());

            Assert.That(first.Count, Is.EqualTo(8));
            Assert.That(second, Is.EqualTo(first));
            Assert.That(first.All(id => id >= 0 && id < 512), Is.True);
        }

        // Trimming is shared by BeginChat and InspectContext, but only InspectContext can be
        // exercised here: the tiny model's 512-token vocabulary cannot accept a real prompt.
        [Test]
        public void ContextTrimsCompleteOldTurnsButKeepsNewestTurn()
        {
            string modelPath = SentisModelPath("Llm_Tiny_Text_128.sentis");
            if (!File.Exists(modelPath))
                Assert.Ignore("Tiny .sentis model not converted yet: " + modelPath);

            ChatServiceOptions options = TinyUncachedOptions(modelPath);
            using ChatService service = new(options);
            service.Start();
            ChatGenerationOptions generation = new() { MaxNewTokens = 8, Temperature = 0f };
            ChatMessage system = ChatMessage.System("Be concise.");
            ChatMessage newest = ChatMessage.User("Newest question.");
            ChatMessage[] history =
            {
                system,
                ChatMessage.User(string.Join(" ", Enumerable.Repeat("old", 200))),
                ChatMessage.Assistant("Old answer."),
                newest,
            };
            int expectedPromptTokens = service
                .Tokenizer.EncodeWithSpecialTokens(
                    ChatTemplate.BuildPromptText(new[] { system, newest })
                )
                .Count;

            ChatContextSnapshot trimmed = service.InspectContext(history, generation);
            Assert.That(trimmed.PromptTokens, Is.EqualTo(expectedPromptTokens));
            Assert.That(trimmed.Messages, Is.EqualTo(new[] { system, newest }));

            // Digits tokenize one-per-digit under the byte-level split regex, so this
            // message can never be BPE-compressed below the 128-token window.
            ChatMessage oversizedNewest = ChatMessage.User(
                string.Join(" ", Enumerable.Range(0, 300))
            );
            Assert.Throws<ArgumentException>(
                () => service.InspectContext(new[] { system, oversizedNewest }, generation)
            );
        }

        [Test]
        public void ContextInspectionKeepsFittingHistoryAndShrinksReplyBudget()
        {
            string modelPath = SentisModelPath("Llm_Tiny_Text_128.sentis");
            if (!File.Exists(modelPath))
                Assert.Ignore("Tiny .sentis model not converted yet: " + modelPath);

            ChatServiceOptions options = TinyUncachedOptions(modelPath);
            using ChatService service = new(options);
            service.Start();
            ChatGenerationOptions generation = new() { MaxNewTokens = 48, Temperature = 0f };
            List<ChatMessage> history =
                new()
                {
                    ChatMessage.System("You are concise."),
                    ChatMessage.User("Call me Jumbo."),
                    ChatMessage.Assistant("Sure."),
                    ChatMessage.User("Who am I now?"),
                };

            int fullPromptTokens = 0;
            for (int repeat = 4; repeat < 80; repeat++)
            {
                history[2] = ChatMessage.Assistant(
                    string.Join(" ", Enumerable.Repeat("friendly detail", repeat))
                );
                fullPromptTokens = service
                    .Tokenizer.EncodeWithSpecialTokens(ChatTemplate.BuildPromptText(history))
                    .Count;
                if (fullPromptTokens >= 88 && fullPromptTokens < 120)
                    break;
            }
            Assert.That(fullPromptTokens, Is.InRange(88, 119));

            ChatContextSnapshot context = service.InspectContext(history, generation);
            Assert.That(context.WasTrimmed, Is.False);
            Assert.That(context.Messages.Count, Is.EqualTo(history.Count));
            Assert.That(context.PromptTokens, Is.EqualTo(fullPromptTokens));
            Assert.That(context.AvailableReplyTokens, Is.LessThan(generation.MaxNewTokens));

            // The prompt fits the window but its ChatML ids run past the tiny model's 512-token
            // vocabulary. Sentis would gather out of bounds and take the process down, so the
            // mismatch has to surface as an exception before anything is scheduled.
            ArgumentException mismatch = Assert.Throws<ArgumentException>(
                () => service.BeginChat(history, generation)
            );
            Assert.That(mismatch.Message, Does.Contain("512-token"));
        }

        [Test]
        public void TinyModelStreamMatchesBlockingGreedyPathAndEmitsTelemetry()
        {
            string modelPath = SentisModelPath("Llm_Tiny_Text_128.sentis");
            if (!File.Exists(modelPath))
                Assert.Ignore("Tiny .sentis model not converted yet: " + modelPath);

            ChatServiceOptions options = TinyUncachedOptions(modelPath);
            using ChatService service = new(options);
            int[] prompt = { 2, 105, 10, 25, 50, 106 };
            ChatGenerationOptions generation = new() { MaxNewTokens = 8, Temperature = 0f };
            List<int> blocking = service.GenerateTokens(prompt, generation, Array.Empty<int>());

            using ChatStream stream = service.BeginStream(prompt, generation, Array.Empty<int>());
            List<int> streamed = new();
            int layersSinceToken = 0;
            int layerEvents = 0;
            int tokenEvents = 0;
            stream.LayerExecuted += (_, _, _) =>
            {
                layersSinceToken++;
                layerEvents++;
            };
            stream.TokenSampled += metrics =>
            {
                Assert.That(layersSinceToken, Is.GreaterThan(0));
                Assert.That(metrics.TopCandidates.Count, Is.GreaterThan(0));
                Assert.That(metrics.WindowCapacity, Is.EqualTo(128));
                streamed.Add(metrics.TokenId);
                layersSinceToken = 0;
                tokenEvents++;
            };

            while (stream.Tick(1000)) { }

            Assert.That(stream.State, Is.EqualTo(ChatStreamState.Completed));
            Assert.That(streamed, Is.EqualTo(blocking));
            Assert.That(tokenEvents, Is.EqualTo(blocking.Count));
            Assert.That(layerEvents, Is.GreaterThanOrEqualTo(tokenEvents));
            Assert.That(stream.Result.FinishReason, Is.EqualTo(ChatFinishReason.TokenLimit));
            Assert.That(stream.Result.IsComplete, Is.False);
        }

        [Test]
        public void TinyModelStreamReportsModelStopAndContextLimitSeparately()
        {
            string modelPath = SentisModelPath("Llm_Tiny_Text_128.sentis");
            if (!File.Exists(modelPath))
                Assert.Ignore("Tiny .sentis model not converted yet: " + modelPath);

            ChatGenerationOptions generation = new() { MaxNewTokens = 8, Temperature = 0f };
            using ChatService service = new(TinyUncachedOptions(modelPath));
            int[] shortPrompt = { 2, 105, 10, 25, 50, 106 };
            int firstToken = service
                .GenerateTokens(shortPrompt, generation, Array.Empty<int>())
                .First();

            using (ChatStream stopped = service.BeginStream(
                shortPrompt,
                generation,
                new[] { firstToken }
            ))
            {
                while (stopped.Tick(1000)) { }
                Assert.That(stopped.Result.FinishReason, Is.EqualTo(ChatFinishReason.StopToken));
                Assert.That(stopped.Result.IsComplete, Is.True);
                Assert.That(stopped.GeneratedIds, Is.Empty);
            }

            int[] nearlyFullPrompt = Enumerable.Repeat(2, 126).ToArray();
            using ChatStream contextLimited = service.BeginStream(
                nearlyFullPrompt,
                generation,
                Array.Empty<int>()
            );
            while (contextLimited.Tick(1000)) { }

            Assert.That(contextLimited.GeneratedIds.Count, Is.EqualTo(2));
            Assert.That(
                contextLimited.Result.FinishReason,
                Is.EqualTo(ChatFinishReason.ContextLimit)
            );
            Assert.That(contextLimited.Result.IsComplete, Is.False);
        }

