        [Test]
        public void TinyKvCacheRetainsPrefixAcrossTurnsAndMatchesRebuild()
        {
            string decodePath = SentisModelPath("Llm_Tiny_Decode_128.sentis");
            if (!File.Exists(decodePath))
                Assert.Ignore("Tiny cached decode model not converted yet: " + decodePath);

            int[] prompt = { 2, 105, 10, 25, 50, 106 };
            ChatGenerationOptions generation = new() { MaxNewTokens = 4, Temperature = 0f };
            List<int> continued;
            int[] extended;
            using (ChatService retained = new(CachedTinyOptions(decodePath)))
            {
                List<int> first = retained.GenerateTokens(prompt, generation, Array.Empty<int>());
                extended = prompt.Concat(first).Concat(new[] { 7, 8 }).ToArray();
                continued = retained.GenerateTokens(extended, generation, Array.Empty<int>());
            }

            using ChatService rebuilt = new(CachedTinyOptions(decodePath));
            List<int> rebuiltResult = rebuilt.GenerateTokens(
                extended,
                generation,
                Array.Empty<int>()
            );
            Assert.That(continued, Is.EqualTo(rebuiltResult));
        }

