        [UnityTest]
        public IEnumerator TinyKvCacheGpuStreamUsesBatchedSchedulingAndMatchesBlockingPath()
        {
            string decodePath = SentisModelPath("Llm_Tiny_Decode_128.sentis");
            if (!File.Exists(decodePath))
                Assert.Ignore("Tiny cached decode model not converted yet: " + decodePath);
            if (!SystemInfo.supportsComputeShaders)
                Assert.Ignore("GPUCompute is unavailable on this system.");

            int[] prompt = { 2, 105, 10, 25, 50, 106 };
            ChatGenerationOptions generation = new() { MaxNewTokens = 6, Temperature = 0f };
            List<int> blocking;
            using (
                ChatService blockingService =
                    new(CachedTinyOptions(decodePath, BackendType.GPUCompute))
            )
                blocking = blockingService.GenerateTokens(prompt, generation, Array.Empty<int>());

            using ChatService streamingService =
                new(CachedTinyOptions(decodePath, BackendType.GPUCompute));
            using ChatStream stream = streamingService.BeginStream(
                prompt,
                generation,
                Array.Empty<int>()
            );
            int layerEvents = 0;
            int forwardEvents = 0;
            stream.LayerExecuted += (_, _, _) => layerEvents++;
            stream.ForwardEvaluated += () => forwardEvents++;
            while (stream.Tick(1000))
                yield return null;

            Assert.That(stream.State, Is.EqualTo(ChatStreamState.Completed));
            Assert.That(stream.GeneratedIds, Is.EqualTo(blocking));
            int forwardCount = prompt.Length + stream.GeneratedIds.Count - 1;
            Assert.That(layerEvents, Is.EqualTo(forwardCount));
            Assert.That(forwardEvents, Is.EqualTo(forwardCount));
        }

