        [Test]
        public void CortexChatEnterRemovesOnlyTheNewlineInsertedByTmp()
        {
            const System.Reflection.BindingFlags flags =
                System.Reflection.BindingFlags.Static | System.Reflection.BindingFlags.NonPublic;
            System.Reflection.MethodInfo method = typeof(CortexChatController).GetMethod(
                "RemoveInsertedNewline",
                flags
            );

            Assert.That(method, Is.Not.Null);
            Assert.That(method.Invoke(null, new object[] { "hello\n", 6 }), Is.EqualTo("hello"));
            Assert.That(
                method.Invoke(null, new object[] { "hello\nworld", 6 }),
                Is.EqualTo("helloworld")
            );
            Assert.That(method.Invoke(null, new object[] { "hello", 5 }), Is.EqualTo("hello"));
        }

