        [UnityTest]
        [Explicit("Loads the production uint8 decode artifact and runs end-to-end generation.")]
        [Timeout(3600000)]
        public IEnumerator FullModelAnswersPong()
        {
            string modelPath = SentisModelPath("Llm_Text_2048.sentis");
            string decodePath = SentisModelPath("Llm_Decode_2048.sentis");
            if (!File.Exists(modelPath) && !File.Exists(decodePath))
                Assert.Ignore("No full LLM .sentis model has been converted yet.");

            ChatServiceOptions options = SystemSettings.CreateServiceOptions(
                LlmSystemOption.Gpu1_7B_2048
            );
            using ChatService service = new(options);
            using ChatStream stream = service.BeginChat(
                new[]
                {
                    ChatMessage.System("You are concise."),
                    ChatMessage.User("Reply with exactly PONG."),
                },
                new ChatGenerationOptions
                {
                    MaxNewTokens = 8,
                    Temperature = 0f,
                    EnableThinking = false,
                }
            );
            List<double> tokenSeconds = new();
            stream.TokenSampled += metrics =>
            {
                if (!metrics.IsStopToken)
                    tokenSeconds.Add(metrics.ElapsedSeconds);
            };
            while (stream.Tick(1000))
                yield return null;

            ChatResult result = stream.Result;
            Assert.That(tokenSeconds, Is.Not.Empty);
            double tokenRate = tokenSeconds.Count / tokenSeconds.Sum();
            TestContext.Out.WriteLine(
                $"GPU stream: {tokenSeconds.Count} tokens at {tokenRate:0.00} token/s "
                    + $"({tokenSeconds.Average():0.000}s/token mean)."
            );

            Assert.That(result.Content, Does.Contain("PONG"));
            Assert.That(result.GeneratedTokens, Is.GreaterThan(0));
        }

        static List<ChatMessage> FixtureMessages()
        {
            return Fixtures
                .chatMessages.Select(message => new ChatMessage(message.role, message.content))
                .ToList();
        }

        static void AssertStreamingResponse(
            string raw,
            string expectedContent,
            string expectedThinking,
            bool expectedThinkingStarted
        )
        {
            const System.Reflection.BindingFlags flags =
                System.Reflection.BindingFlags.Static | System.Reflection.BindingFlags.NonPublic;
            System.Reflection.MethodInfo method = typeof(ChatService).GetMethod(
                "ParseStreamingResponse",
                flags
            );
            object[] arguments = { raw, null, null, false };

            method.Invoke(null, arguments);

            Assert.That(arguments[1], Is.EqualTo(expectedContent));
            Assert.That(arguments[2], Is.EqualTo(expectedThinking));
            Assert.That(arguments[3], Is.EqualTo(expectedThinkingStarted));
        }

        static ChatServiceOptions CachedTinyOptions(
            string decodePath,
            BackendType backend = BackendType.CPU
        )
        {
            ChatServiceOptions options = SystemSettings.CreateServiceOptions(LlmSystemOption.Tiny);
            options.DecodeModelPath = decodePath;
            options.Backend = backend;
            return options;
        }

        static ChatServiceOptions TinyUncachedOptions(string modelPath)
        {
            ChatServiceOptions options = SystemSettings.CreateServiceOptions(LlmSystemOption.Tiny);
            options.ModelPath = modelPath;
            options.DecodeModelPath = null;
            options.Backend = BackendType.CPU;
            return options;
        }
    }
